\begin{itemize}
\item for all $\vect{i}\in\Z^d$ there exists $\vect{i'}\in\M$ such that $\vect{i}\in\vect{i}'+[0,N]^{d}$;
\item for all $\vect{i}\in\M$ one has $z^{\star}_{\vect{i}}\ne \overline{z^{\star}}_{\vect{i}}$ and $z^{\star}_{\vect{i}-\vect{e_l}} =\overline{z^{\star}}_{\vect{i}-\vect{e_l}}$ for all $l\in[1,d]$;
\item for all $\vect{i}\notin\M+[0,N']^d$ one has $z^{\star}_{\vect{i}}= \overline{z^{\star}}_{\vect{i}}$;
\item moreover, \[\textrm{for all $z\in\A^{\Z^{d}}$ which verifies }
\begin{cases}
\textrm{ $z_{\vect{i}}= z^{\star}_{\vect{i}}$} &\textrm{ for all $\vect{i}\notin\M+[0,N']^d$, }\\
\textrm{ $z_{\vect{i}+[0,N']^{d}}=z^{\star}_{\vect{i}+[0,N']^{d}}$ or $\overline{z^{\star}}_{\vect{i}+[0,N']^{d}}$}&\textrm{ for all $\vect{i}\in\M$,}
\end{cases}
\textrm{ one has $z\in\Sigma'$.}\]
\end{itemize}

One says that $\Sigma$ verifies the conditions $\widetilde{\mathcal{H}}$ if moreover there exists a morphism $\psi:\Sigma'\to\Sigma'$ such that for all $z^{\ast}\in\Sigma'$ one can take $\overline{z^{\ast}}=\psi(z^{\ast})$.

